-- Import generated from C:/Users/perry/Downloads/Meal plan 2025 - Usual stats.pdf
-- All nutrition values are stored per 100g. Serving weights in grams were normalised to 100g.
begin;

on conflict (user_id, name) do update set
  calories_per_unit = excluded.calories_per_unit,
  kj_per_unit = excluded.kj_per_unit,
  protein_per_unit = excluded.protein_per_unit,
  unit_label = excluded.unit_label,
  unit_weight_g = excluded.unit_weight_g,
  notes = excluded.notes;

commit;
